import React from "react";
import { AbsoluteFill, interpolate, spring, useCurrentFrame, useVideoConfig } from "remotion";

export const MetricsPulseCard: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();
  const entrance = spring({ frame, fps, config: { damping: 18, stiffness: 160 } });
  const metric = Math.round(interpolate(frame, [0, 60], [78, 91], { extrapolateLeft: "clamp", extrapolateRight: "clamp" }));

  return (
    <AbsoluteFill style={{ backgroundColor: "#07111f", justifyContent: "center", alignItems: "center", fontFamily: "Inter, sans-serif" }}>
      <div style={{ width: 760, borderRadius: 32, padding: 48, backgroundColor: "#0f1b2e", color: "white", transform: `scale(${0.92 + entrance * 0.08})`, boxShadow: "0 30px 80px rgba(0,0,0,0.35)" }}>
        <div style={{ fontSize: 20, letterSpacing: 2, textTransform: "uppercase", opacity: 0.7 }}>Weekly Activation</div>
        <div style={{ display: "flex", alignItems: "center", gap: 20, marginTop: 18 }}>
          <div style={{ fontSize: 120, fontWeight: 700, lineHeight: 1 }}>{metric}</div>
          <div style={{ padding: "10px 16px", borderRadius: 999, backgroundColor: "#163a2f", color: "#8ef0bb", fontSize: 28, fontWeight: 600 }}>+16.7%</div>
        </div>
      </div>
    </AbsoluteFill>
  );
}

import React from "react";
import { AbsoluteFill, spring, useCurrentFrame, useVideoConfig } from "remotion";

const ITEMS = [
  { label: "Onboarding", value: 68 },
  { label: "Activation", value: 84 },
  { label: "Retention", value: 57 },
];

export const ThreeBarStory: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  return (
    <AbsoluteFill style={{ backgroundColor: "#f6f1e8", padding: 88, fontFamily: "Inter, sans-serif", color: "#1f1f1f" }}>
      <div style={{ fontSize: 58, fontWeight: 700 }}>Funnel Health Snapshot</div>
      <div style={{ display: "flex", gap: 36, alignItems: "flex-end", flex: 1, marginTop: 48 }}>
        {ITEMS.map((item, index) => {
          const progress = spring({ frame: frame - index * 8, fps, config: { damping: 16, stiffness: 140 } });
          return (
            <div key={item.label} style={{ flex: 1, display: "flex", flexDirection: "column", justifyContent: "flex-end", gap: 18 }}>
              <div style={{ fontSize: 34, fontWeight: 700 }}>{item.value}%</div>
              <div style={{ height: Math.max(18, item.value * 4 * progress), borderRadius: 24, backgroundColor: index === 1 ? "#ef6c57" : "#2a2a2a" }} />
              <div style={{ fontSize: 28 }}>{item.label}</div>
            </div>
          );
        })}
      </div>
    </AbsoluteFill>
  );
}

import React from "react";
import { AbsoluteFill, spring, useCurrentFrame, useVideoConfig } from "remotion";

export const QuoteCardFocusPull: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();
  const reveal = spring({ frame, fps, config: { damping: 18, stiffness: 120 } });

  return (
    <AbsoluteFill style={{ backgroundColor: "#f6efe6", justifyContent: "center", padding: 72, fontFamily: "Inter, sans-serif", color: "#111111" }}>
      <div style={{ transform: `scale(${0.96 + reveal * 0.04})`, filter: `blur(${(1 - reveal) * 8}px)` }}>
        <div style={{ fontSize: 76, lineHeight: 1.08, fontWeight: 700, maxWidth: 820 }}>
          Good motion makes the idea feel inevitable before the words finish explaining it.
        </div>
        <div style={{ marginTop: 32, fontSize: 28, letterSpacing: 2, textTransform: "uppercase", opacity: 0.7 }}>
          Design Notes
        </div>
      </div>
    </AbsoluteFill>
  );
}
